function main({arg1, arg2}) {
  const result = [...arg1]
  if (arg1 == null || arg1.length === 0) {
    // 如果召回项目的准确率不是很高，则加上数据库查询到的记录
    arg2.forEach((ele) => {
      if (arg1.some(item => item.prj_code === ele.prj_code) === false) {
        result.push(ele)
      }
    })
  }

  return {
    '项目对象_合并': result
  }
}

